  'weifang/kite': ('เมืองหลวงแห่งว่าว', 'เมืองหลวงแห่งว่าวของโลกที่จัดเทศกาลว่าวนานาชาติขึ้นทุกเดือนเมษายนจนเต็มท้องฟ้า'),
  'weifang/woodprint': ('ภาพพิมพ์ไม้หยางเจียปู้', 'หมู่บ้านแห่งนี้สืบทอดการทำภาพพิมพ์ไม้สำหรับเทศกาลตรุษจีนมานานกว่า 600 ปี'),
  'weifang/dragon': ('ว่าวมังกร', 'ว่าวมังกรที่มีความยาวกว่าร้อยเมตรถือเป็นไฮไลท์สำคัญของเทศกาลว่าว'),
  'weifang/radish': ('หัวไชเท้าเหวยฟาง', 'หัวไชเท้าสีเขียวที่สามารถรับประทานสดได้เหมือนผลไม้ถือเป็นของดีขึ้นชื่อของเมือง'),
  'dezhou/chicken': ('ไก่ตุ๋นเต๋อโจว', 'ไก่ตุ๋นเนื้อนุ่มจนหลุดจากกระดูกเมนูนี้เคยเป็นอาหารที่ถวายแด่จักรพรรดิในสมัยก่อน'),
  'dezhou/sun': ('โซลาร์วัลเลย์', 'ที่นี่เป็นที่ตั้งของหนึ่งในวิทยาเขตพลังงานแสงอาทิตย์ที่ใหญ่ที่สุดในโลก'),
  'dezhou/grapes': ('สวนเมลอนและองุ่น', 'พื้นที่ราบอันอุดมสมบูรณ์แห่งนี้เต็มไปด้วยเมลอนและองุ่นในช่วงฤดูร้อน'),
  'dezhou/train': ('ท่าเรือคลองขุด', 'ในอดีตที่นี่เคยเป็นท่าเรือขนส่งธัญพืชที่คึกคักที่สุดแห่งหนึ่งในยุคคลองต้ายวิ่นเหอ'),
  'xuzhou/stone': ('ภาพสลักหินสมัยราชวงศ์ฮั่น', 'แผ่นหินจากสุสานสมัยราชวงศ์ฮั่นช่วยถ่ายทอดภาพวิถีชีวิตของผู้คนเมื่อ 2,000 ปีก่อน'),
  'xuzhou/terracotta': ('กองทัพทหารดินเผา', 'มีการขุดพบกองทัพทหารดินเผาที่มีขนาดเล็กกว่าแต่เก่าแก่กว่าที่นี่'),
  'xuzhou/lake': ('ทะเลสาบอวิ๋นหลง', 'พื้นที่ริมทะเลสาบอวิ๋นหลงเปรียบเสมือนปอดสีเขียวของเมือง'),
  'xuzhou/skewer': ('วัฒนธรรมปิ้งย่าง', 'เมืองนี้ได้ชื่อว่าเป็นเมืองหลวงแห่งการปิ้งย่างของจีน ซึ่งมีเนื้อแกะเสียบไม้ย่างบนเตาถ่านตลอดทั้งคืน'),
  'zhenjiang/vinegar': ('จิ๊กโฉ่วเจิ้นเจียง', 'น้ำส้มสายชูดำจากข้าวเหนียวที่มีชื่อเสียงที่สุดของจีนแห่งนี้ผ่านการหมักบ่มมานานกว่า 1,400 ปี'),
  'zhenjiang/temple': ('วัดจินซาน', 'วัดที่เป็นฉากในตำนานนางพญางูขาวแห่งนี้ตั้งตระหง่านอยู่ริมแม่น้ำ'),
  'zhenjiang/pot': ('บะหมี่ฝาหม้อ', 'บะหมี่ฝาหม้อที่ปรุงโดยใช้ฝาหม้อปิดทับขณะต้มเป็นเมนูอาหารเช้าขึ้นชื่อของท้องถิ่น'),
  'zhenjiang/bridge': ('ริมฝั่งแม่น้ำแยงซี', 'พื้นที่ริมแม่น้ำบริเวณสามขุนเขาถูกล้อมรอบไปด้วยสวนสาธารณะสำหรับเดินเล่น'),
  'jiaxing/zongzi': ('บ๊ะจ่าง', 'ที่นี่คือเมืองหลวงของบ๊ะจ่างหรือข้าวเหนียวห่อใบไผ่ที่มีชื่อเสียง'),
  'jiaxing/boat': ('เรือแดงแห่งทะเลสาบหนานหู', 'ในปี ค.ศ. 1921 การประชุมสมัชชาพรรคครั้งแรกได้จัดขึ้นบนเรือลำหนึ่งในทะเลสาบแห่งนี้'),
  'jiaxing/silk': ('เมืองแห่งผ้าไหม', 'ผ้าไหมเจียงหนานถูกทอขึ้นในเมืองริมคลองแห่งนี้มานานหลายศตวรรษ'),
  'jiaxing/canal': ('เมืองโบราณอูเจิ้น', 'ล่องเรือชมเมืองโบราณที่เต็มไปด้วยสะพานหินและแสงไฟจากโคมสีแดง'),
  'lishui/mountains': ('ยอดเขาเขียวขจี', 'พื้นที่ที่เต็มไปด้วยภูเขามากที่สุดในมณฑลเจ้อเจียง ซึ่งมีหมู่บ้านบนนาขั้นบันไดที่สูงเสียดฟ้า'),
  'lishui/camera': ('สวรรค์ของช่างภาพ', 'นาขั้นบันไดท่ามกลางสายหมอกเป็นหนึ่งในทิวทัศน์ที่ถูกถ่ายภาพมากที่สุดในจีน'),
  'lishui/mushroom': ('ดินแดนแห่งเห็ด', 'อำเภอชิงหยวนเป็นแหล่งกำเนิดการเพาะเห็ดที่สำคัญที่สุดของโลก'),
  'lishui/raft': ('ล่องแพไม้ไผ่', 'ล่องแพไม้ไผ่ไปตามแม่น้ำโอวเจียงเพื่อชมความงามของหุบเขาเขียวขจี'),
  'anqing/opera': ('งิ้วหวงเหมย', 'ศิลปะการแสดงงิ้วท้องถิ่นที่เป็นที่รักมากที่สุดของจีนได้ถือกำเนิดขึ้นที่นี่'),
  'anqing/pagoda': ('เจดีย์เจิ้นเฟิง', 'เจดีย์เก่าแก่อายุกว่า 400 ปีริมแม่น้ำแยงซีที่ได้รับฉายาว่าเป็นประภาคารแห่งแรกของแม่น้ำ'),
  'anqing/tea': ('ชาเยว่ซี', 'ชาเขียวรสเลิศที่มีกลิ่นหอมละมุนซึ่งปลูกบนไหล่เขาต้าเปี๋ย'),
  'anqing/sail': ('ประตูแม่น้ำ', 'เมืองท่าสำคัญริมแม่น้ำแยงซีในมณฑลอันฮุย ซึ่งชื่อเมืองมีความหมายว่าการเฉลิมฉลองอย่างสงบสุข'),
  'ganzhou/orange': ('ส้มนาเวลก้านหนาน', 'ส้มนาเวลที่ขึ้นชื่อว่าหวานที่สุดในจีนเติบโตได้ดีในดินสีแดงของที่นี่'),
  'ganzhou/house': ('บ้านดินชาวฮากกา', 'วัฒนธรรมชาวฮากกาที่สืบทอดมานานหลายศตวรรษในบ้านป้อมปราการทรงกลม'),
  'ganzhou/pavilion': ('ศาลาอวี้กู', 'ศาลาที่กวีสมัยราชวงศ์ซ่งเคยแต่งบทกวีถึง ซึ่งตั้งอยู่บนจุดชมวิวที่แม่น้ำสองสายมาบรรจบกัน'),
  'ganzhou/star': ('การเดินทัพทางไกล', 'เมืองนี้เป็นจุดเริ่มต้นของการเดินทัพทางไกลของกองทัพแดง'),
  'putian/shrine': ('ศาลเจ้าแม่หม่าโจ้ว', 'เจ้าแม่หม่าโจ้วเทพผู้คุ้มครองชาวเรือประสูติที่นี่ และมีศาลเจ้าหลักตั้งอยู่บนเกาะเหมยโจว'),
  'putian/lychee': ('สวนลิ้นจี่', 'ต้นลิ้นจี่อายุนับพันปีทำให้เมืองนี้ได้รับฉายาว่าเป็นดินแดนแห่งลิ้นจี่'),
  'putian/shoe': ('เมืองหลวงแห่งรองเท้า', 'สัดส่วนการผลิตรองเท้ากีฬาจำนวนมหาศาลของโลกมาจากโรงงานในเมืองนี้'),
  'putian/wave': ('เกาะเหมยโจว', 'เกาะที่เดินทางไปถึงได้ด้วยเรือเฟอร์รี่แห่งนี้มีชื่อเสียงในเรื่องชายหาดและเทศกาลงานวัด'),
  'mudanjiang/snow': ('หมู่บ้านหิมะ', 'หมู่บ้านในเทพนิยายที่ถูกปกคลุมด้วยหิมะหนานุ่มและส่องประกายงดงามในฤดูหนาว'),
  'mudanjiang/lake': ('ทะเลสาบจิ้งปัว', 'ทะเลสาบที่เกิดจากการระเบิดของภูเขาไฟซึ่งมีน้ำตกเตี้ยวสุ่ยโหลวที่ยังคงไหลแม้ในฤดูหนาว'),
  'mudanjiang/tiger': ('สวนเสือไซบีเรีย', 'หนึ่งในเขตรักษาพันธุ์เสือไซบีเรียที่ใหญ่ที่สุดในโลก'),
  'mudanjiang/ski': ('ฤดูกาลเล่นสกี', 'ฤดูหนาวที่มีหิมะตกยาวนานทำให้ภูมิภาคนี้เป็นจุดหมายปลายทางของนักสกีทุกคน'),
  'changzhou/dino': ('สวนสนุกไดโนเสาร์', 'สวนสนุกธีมไดโนเสาร์ที่มีชื่อเสียงที่สุดของจีนและเป็นสัญลักษณ์สำหรับครอบครัวของเมืองนี้'),
  'changzhou/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์ที่สูงที่สุดในโลกด้วยความสูง 153 เมตรตั้งตระหง่านอยู่ใจกลางเมือง'),
  'changzhou/comb': ('งานหัตถกรรมหวี', 'หวีจากฉางโจวที่มีประวัติศาสตร์ยาวนานนับพันปีเคยเป็นของขวัญล้ำค่าในราชสำนัก'),
  'changzhou/canal': ('คลองต้ายวิ่นเหอ', 'ริมฝั่งคลองเป็นจุดเดินเล่นยอดนิยมเพื่อชมย่านเมืองเก่าและแสงสีในยามค่ำคืน'),
  'shaoxing/wine': ('เหล้าเส้าซิง', 'เหล้าข้าวสีเหลืองที่มีชื่อเสียงในการปรุงอาหารจีนซึ่งมีการหมักบ่มที่นี่มานานนับพันปี'),
  'shaoxing/bridge': ('สะพานหินโบราณ', 'เมืองเส้าซิงที่เต็มไปด้วยลำคลองยังคงอนุรักษ์สะพานหินโค้งไว้หลายร้อยแห่ง'),
  'shaoxing/pen': ('แหล่งกำเนิดอักษรวิจิตร', 'ศาลาหลานถิงของปรมาจารย์หวังซีจือถือเป็นสถานที่ศักดิ์สิทธิ์ของศิลปะการเขียนพู่กันจีน'),
  'shaoxing/boat': ('เรืออูเผิง', 'เรือหลังคาดำที่ใช้เท้าพายคือพาหนะสุดคลาสสิกในการล่องไปตามลำคลอง'),
  'bengbu/shell': ('ท่าเรือไข่มุก', 'ชื่อเมืองมีความหมายว่าท่าเรือหอย ซึ่งในอดีตเคยมีชื่อเสียงโด่งดังจากการเป็นแหล่งไข่มุกแห่งแม่น้ำหวย'),
  'bengbu/train': ('สถานีรถไฟเปิ่งปู้', 'เมืองนี้เติบโตขึ้นจากการเป็นจุดเชื่อมต่อสำคัญของเส้นทางรถไฟสายเหนือ-ใต้ที่ตัดผ่านแม่น้ำหวย'),
  'bengbu/river': ('แม่น้ำหวย', 'แม่น้ำสายสำคัญที่เป็นเส้นแบ่งเขตทางภูมิศาสตร์ระหว่างจีนเหนือและจีนใต้ไหลผ่านเมืองนี้'),
  'bengbu/blossom': ('เทศกาลชมดอกไม้', 'สวนสาธารณะริมแม่น้ำจะเต็มไปด้วยสีสันของเทศกาลชมดอกไม้ในช่วงฤดูใบไม้ผลิ'),
  'jiujiang/mountain': ('เขาหลูซาน', 'ยอดเขาที่ปกคลุมด้วยหมอกของเขาหลูซานได้รับการขึ้นทะเบียนเป็นมรดกโลกและเป็นแรงบันดาลใจให้แก่กวีและจิตรกรมากมาย'),
  'jiujiang/tea': ('ชาอวิ๋นอู้', 'ชาอวิ๋นอู้ที่ปลูกบนไหล่เขาหลูซานถือเป็นหนึ่งในชาที่มีรสชาติละมุนที่สุดของจีน'),
  'jiujiang/lake': ('ทะเลสาบโผหยาง', 'ทะเลสาบน้ำจืดที่ใหญ่ที่สุดในจีนแห่งนี้เป็นแหล่งอาศัยของนกกระเรียนนับพันตัวในช่วงฤดูหนาว'),
  'jiujiang/scroll': ('เมืองแห่งบทกวี', 'เมืองท่าริมแม่น้ำแห่งนี้เป็นสถานที่ที่กวีชื่อดังอย่างไป๋จวีอี้และซูซื่อเคยมาพำนักและรังสรรค์บทกวีไว้'),
  'quanzhou/ship': ('เส้นทางสายไหมทางทะเล', 'เมืองท่าที่ยิ่งใหญ่ที่สุดในยุคกลางที่มาร์โค โปโลเรียกว่า \'จื่อตง\' และได้รับการขึ้นทะเบียนเป็นมรดกโลก'),
  'quanzhou/mosque': ('มัสยิดชิงจิ้ง', 'มัสยิดหินที่สร้างขึ้นในปี ค.ศ. 1009 แห่งนี้เป็นหนึ่งในมัสยิดที่เก่าแก่ที่สุดของจีน'),
  'quanzhou/puppet': ('หุ่นกระบอกฉวนโจว', 'ศิลปะการเชิดหุ่นกระบอกของฉวนโจวเป็นมรดกทางวัฒนธรรมบนเวทีที่มีประวัติศาสตร์ยาวนานนับพันปี'),
  'quanzhou/tea': ('ชาทิกวนอิม', 'ชาอูหลงจากเมืองอันซีที่อยู่ใกล้เคียงเป็นชาที่มีชื่อเสียงระดับโลกในชื่อ \'พระโพธิสัตว์เหล็ก\''),
  'shanghai/pearl': ('หอไข่มุกตะวันออก', 'หอคอยที่มีรูปทรงลูกบอลสีชมพูโดดเด่นริมแม่น้ำหวงผู่แห่งนี้เป็นสัญลักษณ์ของเซี่ยงไฮ้ยุคใหม่'),
  'shanghai/bund': ('เดอะบันด์', 'ย่านริมน้ำที่มีอาคารสถาปัตยกรรมเก่าแก่สะท้อนให้เห็นถึงความรุ่งเรืองของเซี่ยงไฮ้ในอดีต'),
  'shanghai/garden': ('สวนอวี้หยวน', 'สวนสไตล์จีนดั้งเดิมจากสมัยราชวงศ์หมิงที่เต็มไปด้วยโขดหินและสระน้ำ เปรียบเสมือนโอเอซิสใจกลางเมือง'),
  'shanghai/xlb': ('เสี่ยวหลงเปา', 'ซาลาเปาลูกเล็กที่อัดแน่นด้วยน้ำซุปร้อนๆ คือเมนูเด็ดที่เป็นเอกลักษณ์ของมื้อเช้าในเซี่ยงไฮ้'),
  'hangzhou/lake': ('ทะเลสาบซีหู', 'ทะเลสาบแห่งนี้เต็มไปด้วยทิวทัศน์ของต้นหลิว เกาะน้อยใหญ่ และสะพานโค้ง ซึ่งได้รับการยกย่องในบทกวีจีนมากที่สุด'),
  'hangzhou/tea': ('ชาหลงจิ่ง', 'ชาเขียวหลงจิ่งที่ปลูกบนเนินเขาโดยรอบทะเลสาบถือเป็นชาที่มีชื่อเสียงที่สุดของประเทศจีน'),
  'hangzhou/temple': ('วัดหลิงอิ่น', 'วัดเก่าแก่อายุกว่า 1,700 ปีแห่งนี้มีชื่อเสียงโด่งดังจากงานแกะสลักหินและองค์พระพุทธรูปขนาดใหญ่'),
  'hangzhou/silk': ('เมืองผ้าไหม', 'ผ้าไหมหางโจวมีการทอมายาวนานนับพันปีและเป็นสัญลักษณ์แห่งความมั่งคั่งของจุดเริ่มต้นเส้นทางสายไหมทางตะวันออก'),
  'chongqing/hongya': ('ถ้ำหงหยา', 'กลุ่มอาคารบ้านเรือนบนเสาเข็มที่เกาะอยู่ริมหน้าผาแห่งนี้จะส่องแสงระยิบระยับราวกับเมืองในเทพนิยายยามค่ำคืน'),
  'chongqing/hotpot': ('หม่าล่าหม้อไฟฉงชิ่ง', 'หม้อไฟที่เดือดพล่านไปด้วยน้ำมันเผ็ดร้อนและพริกหม่าล่าคือจิตวิญญาณอันร้อนแรงของเมืองแห่งขุนเขาแห่งนี้'),
  'chongqing/monorail': ('รถไฟฟ้ารางเดี่ยว', 'รถไฟฟ้าที่วิ่งทะลุผ่านตัวอาคารเป็นภาพจำอันเป็นเอกลักษณ์ของเมืองที่สร้างขึ้นบนภูเขาแห่งนี้'),
  'chongqing/river': ('ช่องเขาแยงซี', 'ท่าเรือแห่งนี้เป็นจุดเริ่มต้นของการล่องเรือชมช่องเขาแยงซี ซึ่งเป็นจุดที่เมืองตั้งตระหง่านอยู่ตรงจุดบรรจบของแม่น้ำสองสาย'),
  'dalian/square': ('จัตุรัสซิงไห่', 'จัตุรัสกลางเมืองที่ใหญ่ที่สุดในเอเชียแห่งนี้เป็นสถานที่จัดงานเทศกาลและการแสดงต่างๆ ริมชายฝั่งทะเล'),
  'dalian/beach': ('ชายหาดต้าเหลียน', 'ด้วยเวิ้งอ่าวหินและอากาศที่เย็นสบายในฤดูร้อน ทำให้ต้าเหลียนเป็นเมืองตากอากาศริมทะเลที่ได้รับความนิยมมากที่สุดในภาคเหนือ'),
  'dalian/football': ('เมืองแห่งฟุตบอล', 'ที่นี่เปรียบเสมือนแหล่งกำเนิดฟุตบอลของจีนและเป็นบ้านเกิดของสโมสรฟุตบอลที่ประสบความสำเร็จมากที่สุดในประเทศ'),
  'dalian/seafood': ('อาหารทะเล', 'หอยเชลล์ กุ้ง และหอยเม่นจากทะเลเหลืองที่เย็นจัดเป็นวัตถุดิบชั้นเลิศที่ประดับอยู่บนโต๊ะอาหารของเมืองนี้'),
  'shenyang/palace': ('พระราชวังมุกเดน', 'พระราชวังแห่งแรกของราชวงศ์ชิง ซึ่งเปรียบเสมือนน้องชายขนาดกะทัดรัดของพระราชวังต้องห้ามในปักกิ่ง'),
  'shenyang/tomb': ('สุสานราชวงศ์ชิง', 'สุสานทางทิศตะวันออกและทิศเหนือที่ล้อมรอบเมืองเป็นที่ตั้งของอนุสรณ์สถานฝังพระศพผู้ก่อตั้งราชวงศ์'),
  'shenyang/factory': ('แหล่งกำเนิดอุตสาหกรรมหนัก', 'ที่นี่คือจุดเริ่มต้นของอุตสาหกรรมหนักในจีน โดยมีโรงงานขนาดใหญ่มากมายจนได้รับฉายาว่าเป็นรูห์รแห่งตะวันออก'),
  'shenyang/dumpling': ('เกี๊ยวเหล่าเปียน', 'เกี๊ยวนึ่งสูตรเหล่าเปียนที่มีประวัติยาวนานกว่าสองร้อยปีถือเป็นเมนูขึ้นชื่อบนโต๊ะอาหารของชาวจีนภาคเหนือ'),
  'hefei/judge': ('ศาลท่านเปา', 'เปาบุ้นจิ้นผู้เป็นสัญลักษณ์แห่งความยุติธรรมถือกำเนิดที่นี่ ศาลแห่งนี้จึงเปรียบเสมือนอนุสรณ์สถานแห่งความซื่อสัตย์สุจริต'),
  'hefei/science': ('เมืองแห่งวิทยาศาสตร์', 'ศูนย์กลางด้านเทคโนโลยีที่รวบรวมมหาวิทยาลัยและห้องปฏิบัติการชั้นนำของจีนไว้มากมาย'),
  'hefei/lake': ('ทะเลสาบเฉาหู', 'หนึ่งในห้าทะเลสาบน้ำจืดที่ใหญ่ที่สุดของจีน ซึ่งมีชื่อเสียงโด่งดังในเรื่องปลาขาวและปู'),
  'hefei/cake': ('ขนมงาหลูโจว', 'ขนมงาสอดไส้รสหวานเป็นของว่างดั้งเดิมที่อยู่คู่กับเมืองหลูโจวมาอย่างยาวนาน'),
  'foshan/wingchun': ('มวยหย่งชุน', 'เมืองนี้เป็นต้นกำเนิดของมวยหย่งชุน ซึ่งเป็นรากฐานวิชาการต่อสู้ของยิปมันและบรูซ ลี'),
  'foshan/lion': ('เชิดสิงโต', 'เมืองหลวงแห่งการเชิดสิงโตแบบกวางตุ้ง ที่ซึ่งสิงโตหลากสีสันจะกระโดดโลดเต้นไปตามเสาในงานเทศกาลต่างๆ'),
  'foshan/ceramic': ('เครื่องปั้นดินเผาฉือวาน', 'เตาเผาที่มีอายุนับพันปียังคงผลิตตุ๊กตาดินเผาฉือวานที่มีชีวิตชีวาจนถึงปัจจุบัน'),
  'foshan/opera': ('งิ้วกวางตุ้ง', 'ศิลปะการแสดงบนเวทีที่เป็นที่รักที่สุดของชาวจีนภาคใต้ได้เติบโตและงอกงามขึ้นบนแผ่นดินแห่งนี้'),
  'guiyang/pavilion': ('ศาลาเจี่ยซิ่ว', 'ศาลาสามชั้นริมแม่น้ำหนานหมิงแห่งนี้เป็นสัญลักษณ์คู่บ้านคู่เมืองกุ้ยหยางมานานกว่า 400 ปี'),
  'guiyang/sourfish': ('ต้มปลาซุปเปรี้ยว', 'ปลาต้มในน้ำซุปสีแดงรสเปรี้ยวจากมะเขือเทศหมักเป็นเมนูที่เป็นเอกลักษณ์ของมณฑลกุ้ยโจว'),
  'guiyang/waterfall': ('น้ำตกหวงกั่วซู่', 'หนึ่งในน้ำตกที่ใหญ่ที่สุดของเอเชียที่ไหลเชี่ยวกรากจนเกิดเป็นสายรุ้งงดงาม'),
  'guiyang/miao': ('วัฒนธรรมชาวม้ง', 'เทศกาลและงานปักผ้าของชาวม้งผู้สวมเครื่องประดับเงินช่วยสร้างสีสันให้กับหมู่บ้านบนภูเขา'),
  'changchun/film': ('เมืองแห่งภาพยนตร์', 'สตูดิโอที่เป็นจุดกำเนิดของวงการภาพยนตร์จีนตั้งอยู่ที่นี่ จนได้รับฉายาว่าเป็นฮอลลีวูดแห่งโลกตะวันออก'),
  'changchun/car': ('เมืองแห่งยานยนต์', 'โรงงานแห่งนี้เป็นที่ผลิตรถยนต์ที่สร้างขึ้นเองคันแรกของจีน จนกลายเป็นเมืองหลวงด้านยานยนต์ของประเทศ'),
  'changchun/palace': ('พระราชวังหุ่นเชิด', 'พระราชวังแห่งนี้เป็นที่ประทับของจักรพรรดิองค์สุดท้ายและเป็นพยานเงียบแห่งประวัติศาสตร์อันผันผวน'),
  'changchun/snow': ('หิมะฤดูหนาว', 'ในช่วงฤดูหนาวอันยาวนาน เมืองทั้งเมืองจะส่องประกายไปด้วยประติมากรรมน้ำแข็งและลานสกี'),
  'xining/lake': ('ทะเลสาบชิงไห่', 'ทะเลสาบน้ำเค็มที่ใหญ่ที่สุดในจีนแห่งนี้มีชื่อเสียงจากทุ่งดอกเรปซีดสีเหลืองอร่ามที่ล้อมรอบในช่วงฤดูร้อน'),
  'xining/monastery': ('วัดคุมบุม', 'หนึ่งในหกวัดที่ยิ่งใหญ่ที่สุดของพุทธศาสนาแบบทิเบต ซึ่งมีชื่อเสียงโด่งดังจากการแกะสลักเนยจามรี'),
  'xining/flower': ('ดอกเรปซีด', 'ในเดือนกรกฎาคม ที่ราบสูงแห่งนี้จะถูกปกคลุมไปด้วยทุ่งดอกเรปซีดสีทองสุดลูกหูลูกตา'),
  'xining/lamb': ('เนื้อจามรีและเนื้อแกะ', 'บะหมี่ดึงมือและเนื้อแกะย่างสไตล์ชาวหุยและชาวทิเบตคือรสชาติที่เป็นเอกลักษณ์ของที่ราบสูงแห่งนี้'),
  'guilin/karst': ('ภูเขาหินปูนแม่น้ำหลี', 'ยอดเขาหินปูนที่โผล่พ้นสายหมอกคือทิวทัศน์ที่ปรากฏอยู่บนธนบัตรใบละ 20 หยวน'),
  'guilin/elephant': ('เขาช้างเผือก', 'โขดหินรูปทรงคล้ายช้างที่กำลังใช้งวงจุ่มน้ำคือสัญลักษณ์อันเป็นที่รักของเมืองนี้'),
  'guilin/terrace': ('นาขั้นบันไดหลงจี๋', 'นาขั้นบันไดสันหลังมังกรที่โอบล้อมไหล่เขาเปรียบเสมือนบันไดที่สร้างขึ้นจากหยาดเหงื่อแรงงานนับศตวรรษ'),
  'guilin/osmanthus': ('ดอกหอมหมื่นลี้', 'ชื่อเมืองกุ้ยหลินแปลว่าป่าหอมหมื่นลี้ ในช่วงฤดูใบไม้ร่วงเมืองทั้งเมืองจะอบอวลไปด้วยกลิ่นหอมหวานของดอกไม้ชนิดนี้'),
  'wenzhou/merchant': ('จิตวิญญาณนักธุรกิจ', 'ผู้ประกอบการชาวเวินโจวได้รับฉายาว่าเป็นชาวยิวแห่งเมืองจีน โดยพวกเขาสร้างเครือข่ายธุรกิจไปทั่วโลก'),
  'wenzhou/shoe': ('รองเท้าและเครื่องหนัง', 'รองเท้าหนังจำนวนมหาศาลที่ใช้กันทั่วโลกล้วนผลิตมาจากเมืองโรงงานแห่งนี้'),
  'wenzhou/mountain': ('ภูเขาเหยียนตั่ง', 'ภูเขาแห่งนี้มีชื่อเสียงจากน้ำตกและยอดเขาที่แหลมคม จนได้รับการยกย่องว่าเป็นภูเขาแห่งแรกริมทะเล'),
  'wenzhou/seafood': ('อาหารทะเล', 'ปลาหมึก หอยเชลล์ และปลาจากทะเลจีนตะวันออกคือวัตถุดิบหลักบนโต๊ะอาหารของชาวเมืองนี้'),
  'tangshan/memorial': ('อนุสรณ์สถานแผ่นดินไหว', 'สวนอนุสรณ์สถานเหตุการณ์แผ่นดินไหวครั้งใหญ่ในปี 1976 คือสัญลักษณ์ของการเกิดใหม่ของเมือง'),
  'tangshan/coal': ('ถ่านหินและเหล็กกล้า', 'ที่นี่เป็นจุดกำเนิดอุตสาหกรรมสมัยใหม่ของจีน โดยเป็นที่ตั้งของเหมืองถ่านหินและทางรถไฟแห่งแรกของประเทศ'),
  'tangshan/ceramic': ('เครื่องปั้นดินเผาถังซาน', 'เมืองแห่งเครื่องลายครามทางตอนเหนือที่มีชื่อเสียงโดดเด่นในเรื่องโบนไชน่าอันประณีตงดงาม'),
  'tangshan/lake': ('สวนสาธารณะหนานหู', 'สวนสาธารณะริมทะเลสาบที่ปรับปรุงจากพื้นที่เหมืองเก่าจนกลายเป็นปอดสีเขียวของเมือง'),
  'anshan/steel': ('เมืองเหล็กกล้า', 'เมืองหลวงแห่งเหล็กกล้าของจีนซึ่งเป็นที่ตั้งของโรงงานผลิตเหล็กที่ใหญ่ที่สุดในประเทศ'),
  'anshan/jade': ('หยกซิ่วเหยียน', 'เมืองแห่งหยกของจีนที่เป็นที่ตั้งของงานแกะสลักหยกที่ใหญ่ที่สุดในโลก'),
  'anshan/mountain': ('เขาเชียนซาน', 'ยอดเขาศักดิ์สิทธิ์ทางตอนเหนือที่เต็มไปด้วยวัดวาอารามและทัศนียภาพของยอดเขาที่สวยงามดั่งดอกบัว'),
  'anshan/spring': ('น้ำพุร้อนถังกังจื่อ', 'แหล่งน้ำพุร้อนเพื่อการบำบัดที่มีประวัติยาวนานนับพันปีและเคยเป็นสถานที่พักผ่อนของเหล่าจักรพรรดิ'),
  'linyi/market': ('ตลาดค้าส่งหลินอี๋', 'ศูนย์กลางการค้าส่งที่ใหญ่ที่สุดในภาคเหนือของจีนซึ่งกระจายสินค้าไปทั่วประเทศ'),
  'linyi/brush': ('ปรมาจารย์พู่กันจีน', 'บ้านเกิดของหวังซีจือ ปราชญ์แห่งอักษรวิจิตรของจีน เมืองนี้จึงได้ชื่อว่าเป็นดินแดนแห่งหมึกและพู่กัน'),
  'linyi/mountain': ('เขาเหมิงซาน', 'ภูเขาที่สูงเป็นอันดับสองของมณฑลซานตง ซึ่งเปรียบเสมือนแหล่งผลิตอากาศบริสุทธิ์ที่เต็มไปด้วยน้ำตก'),
  'linyi/pancake': ('แพนเค้กอี๋เหมิง', 'เจียนปิ่งหรือแพนเค้กแผ่นบางทำจากข้าวโพดที่เป็นอาหารหลักดั้งเดิมของชาวเขาอี๋เหมิง'),
  'cangzhou/lion': ('สิงโตเหล็ก', 'รูปปั้นสิงโตเหล็กหล่อขนาดมหึมาที่มีอายุเก่าแก่กว่า 1,100 ปี ซึ่งเป็นสัญลักษณ์อันภาคภูมิใจของเมือง'),
  'cangzhou/martial': ('ศิลปะการต่อสู้', 'บ้านเกิดแห่งวิทยายุทธของจีนที่เป็นแหล่งกำเนิดของปรมาจารย์และสำนักฝึกศิลปะการต่อสู้ที่มีชื่อเสียง'),
  'cangzhou/canal': ('คลองต้ายวิ่นเหอ', 'คลองขุดปักกิ่ง-หางโจวที่ไหลผ่านตัวเมือง โดยยังคงหลงเหลือร่องรอยของท่าเรือเก่าแก่ให้เห็น'),
  'cangzhou/jujube': ('พุทราทองคำ', 'พุทราสายพันธุ์พิเศษที่มีเปลือกบางและรสหวานฉ่ำ ได้รับการยกย่องว่าเป็นราชาแห่งผลไม้อบแห้ง'),
  'nantong/textile': ('เมืองแห่งสิ่งทอ', 'เมืองนี้เป็นศูนย์กลางอุตสาหกรรมสิ่งทอของจีนที่ส่งออกผ้าฝ้ายไปจำหน่ายทั่วโลก'),
  'nantong/mountain': ('เขาหลางซาน', 'ภูเขาศักดิ์สิทธิ์ห้ายอดที่ตั้งอยู่บริเวณปากแม่น้ำแยงซี เป็นจุดหมายปลายทางยอดนิยมของผู้แสวงบุญและนักท่องเที่ยวที่ต้องการชมวิวทิวทัศน์'),
  'nantong/kite': ('ว่าวนกหวีด', 'ว่าวปั้นเหยาที่มีการติดตั้งนกหวีดเพื่อให้เกิดเสียงหึ่งๆ ขณะลอยอยู่บนฟ้าเป็นงานฝีมือดั้งเดิมของเมืองนี้'),
  'nantong/school': ('ผู้บุกเบิกการศึกษา', 'จางเจียน นักอุตสาหกรรมผู้มีชื่อเสียงได้ก่อตั้งโรงเรียนสมัยใหม่และพิพิธภัณฑ์แห่งแรกของจีนขึ้นที่นี่'),
  'taizhou/opera': ('เหมยหลานฟาง', 'เมืองนี้เป็นบ้านเกิดของเหมยหลานฟาง ปรมาจารย์ผู้เป็นตำนานแห่งงิ้วปักกิ่ง'),
  'taizhou/tea': ('น้ำชายามเช้า', 'วัฒนธรรมการรับประทานอาหารเช้าด้วยซาลาเปานึ่งคู่กับน้ำชาเป็นวิถีชีวิตที่เป็นเอกลักษณ์ของชาวเมือง'),
  'taizhou/boat': ('เทศกาลเรือฉินถง', 'ในช่วงฤดูใบไม้ผลิจะมีเทศกาลแข่งเรือที่เต็มไปด้วยฝีพายหลายร้อยคน ทำให้แม่น้ำกลับมามีชีวิตชีวาอีกครั้ง'),
  'taizhou/meatball': ('หมูสับหัวสิงโต', 'เมนูหมูสับก้อนโตเนื้อนุ่มที่เรียกว่าหัวสิงโตเป็นอาหารขึ้นชื่อระดับตำนานของอาหารสไตล์หวยหยาง'),
  'jinhua/ham': ('แฮมจินหัว', 'แฮมสีแดงที่ผ่านกรรมวิธีการบ่มแบบดั้งเดิมมานานหลายศตวรรษถือเป็นแฮมที่มีชื่อเสียงที่สุดในจีน'),
  'jinhua/film': ('กองถ่ายเหิงเตี้ยน', 'กองถ่ายภาพยนตร์กลางแจ้งที่ใหญ่ที่สุดในโลกแห่งนี้เป็นสถานที่ถ่ายทำละครย้อนยุคจำนวนนับไม่ถ้วน'),
  'jinhua/cave': ('ถ้ำซวงหลง', 'ถ้ำใต้ดินที่ต้องนั่งเรือลอดผ่านช่องหินเตี้ยๆ เข้าไป เป็นสถานที่ที่สร้างความตื่นตาตื่นใจให้แก่ผู้มาเยือน'),
  'jinhua/bridge': ('สะพานโบราณ', 'สะพานหินโค้งและเมืองริมน้ำสะท้อนให้เห็นถึงความงดงามตามแบบฉบับของภูมิภาคเจียงหนาน'),
  'wuhu/park': ('สวนสนุกฟางเท่อ', 'หนึ่งในสวนสนุกที่ใหญ่ที่สุดของจีนแห่งนี้มอบความสนุกสนานตื่นเต้นให้กับครอบครัวได้ตลอดทั้งวัน'),
  'wuhu/ironart': ('ภาพวาดเหล็ก', 'งานศิลปะภาพวาดเหล็กที่ประดิษฐ์ขึ้นจากเหล็กดัดอย่างประณีตเป็นงานฝีมือที่มีประวัติยาวนานกว่า 300 ปี'),
  'wuhu/rice': ('เมืองท่าข้าว', 'เมืองที่ตั้งอยู่ริมแม่น้ำแยงซีแห่งนี้เคยเป็นตลาดค้าข้าวที่ใหญ่ที่สุดของจีนในอดีต'),
  'wuhu/river': ('ท่าเรือแม่น้ำแยงซี', 'ท่าเรือที่คึกคักแห่งนี้เป็นประตูสำคัญที่เชื่อมเมืองอู๋หูออกสู่ทะเล'),
  'huangshan/peak': ('ภูเขาหวงซาน', 'ภูเขาที่มีชื่อเสียงที่สุดของจีนแห่งนี้โดดเด่นด้วยยอดเขาหินแกรนิต ทะเลหมอก และต้นสนรูปร่างแปลกตา'),
  'huangshan/village': ('หมู่บ้านหงชุน', 'หมู่บ้านสไตล์ฮุยที่มีกำแพงสีขาวและลำธารไหลผ่านแห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกและมีความงดงามราวกับภาพวาด'),
  'huangshan/tea': ('ชาเหมาเฟิง', 'ชาเขียวปลายยอดอ่อนที่เก็บเกี่ยวจากบนภูเขาที่มีหมอกปกคลุมแห่งนี้ เป็นหนึ่งในสิบสุดยอดชาที่มีชื่อเสียงที่สุดของจีน'),
  'huangshan/ink': ('หมึกและศิลปะหุยโจว', 'หมึกหุยโจว งานแกะสลักไม้ และศิลปะการเขียนพู่กันจีนถือเป็นสมบัติทางวัฒนธรรมอันล้ำค่าของภูมิภาคนี้'),
  'yichun/moon': ('ภูเขาหมิงเยว่', 'ภูเขาพระจันทร์สว่างแห่งนี้มีชื่อเสียงในเรื่องบ่อน้ำพุร้อนและทิวทัศน์อันสวยงามที่มองเห็นได้จากกระเช้าไฟฟ้า'),
  'yichun/spring': ('น้ำพุร้อน', 'น้ำพุร้อนที่อุดมไปด้วยแร่ธาตุซีลีเนียมหายากทำให้เมืองนี้กลายเป็นศูนย์กลางการแช่น้ำพุร้อนของจีน'),
  'yichun/zen': ('พุทธศาสนานิกายฉาน', 'วัดบนภูเขาที่เป็นรากฐานของนิกายฉานในจีนเชิญชวนให้ผู้คนมาสัมผัสกับความสงบทางจิตใจ'),
  'yichun/rice': ('ที่ราบลุ่มแม่น้ำหยวนเหอ', 'ที่ราบอันอุดมสมบูรณ์แห่งนี้เป็นแหล่งเพาะปลูกข้าวที่สำคัญของมณฑลเจียงซีมาอย่างยาวนาน'),
  'zhangzhou/narcissus': ('ดอกนาร์ซิสซัส', 'แหล่งปลูกดอกนาร์ซิสซัสที่มีชื่อเสียงที่สุดของจีน ซึ่งถือเป็นสัญลักษณ์แห่งเทศกาลฤดูใบไม้ผลิ'),
  'zhangzhou/tulou': ('บ้านดินถู่โหลว', 'ป้อมปราการดินทรงกลมขนาดใหญ่ที่ได้รับการขึ้นทะเบียนเป็นมรดกโลก ซึ่งเป็นที่อยู่อาศัยของคนทั้งหมู่บ้านภายใต้หลังคาเดียวกัน'),
  'zhangzhou/banana': ('ผลไม้เมืองร้อน', 'สวนกล้วย ลำไย และส้มเขียวหวาน ทำให้พื้นที่สามเหลี่ยมปากแม่น้ำแห่งนี้เขียวชอุ่มตลอดทั้งปี'),
  'zhangzhou/coast': ('เกาะตงซาน', 'เกาะที่เป็นดั่งไข่มุกแห่งชายฝั่งทางใต้ โดดเด่นด้วยหาดทรายสีทองและหมู่บ้านชาวประมง'),
  'beijing/great-wall': ('กำแพงเมืองจีน', 'สิ่งก่อสร้างที่ยาวที่สุดในโลกซึ่งสร้างขึ้นเพื่อป้องกันพรมแดนทางเหนือ โดยด่านปาต้าหลิ่งใกล้กรุงปักกิ่งเป็นจุดที่มีนักท่องเที่ยวไปเยือนมากที่สุด'),
  'beijing/temple': ('หอฟ้าเทียนถาน', 'สถานที่ศักดิ์สิทธิ์ที่จักรพรรดิในสมัยราชวงศ์หมิงและชิงใช้ประกอบพิธีบวงสรวงเพื่อขอพรให้พืชผลอุดมสมบูรณ์ โดยมีหลังคาทรงกลมสีน้ำเงินที่สร้างขึ้นโดยไม่ใช้ตะปูแม้แต่ตัวเดียว'),
  'beijing/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์อิฐทรงแปดเหลี่ยมสูง 57 เมตรจากสมัยราชวงศ์เหลียวแห่งนี้เป็นหนึ่งในสิ่งก่อสร้างที่เก่าแก่ที่สุดในปักกิ่ง ซึ่งเป็นประจักษ์พยานแห่งประวัติศาสตร์อันยาวนานนับพันปีของเมือง'),
  'beijing/opera': ('งิ้วปักกิ่ง', 'ศิลปะการแสดงดั้งเดิมของจีนที่มีอายุกว่า 200 ปี ซึ่งผสมผสานทั้งการร้อง การพูด ศิลปะการต่อสู้ และกายกรรมเข้าด้วยกัน โดยสีบนใบหน้าของนักแสดงจะบ่งบอกถึงอุปนิสัยของตัวละคร เช่น สีแดงสื่อถึงความซื่อสัตย์ และสีขาวสื่อถึงความเจ้าเล่ห์'),
};
